const { AzureFunction } = require('@azure/functions');

module.exports = new AzureFunction({
  timeout: 600000, // 10 minutes for Consumption plan
  disableTimeoutEnforcement: true,
  handler: async (context) => {
    const cosmosDbClient = context.getCosmosDbClient();
    const databaseName = 'my-database';
    const collectionName = 'my-collection';
    const query = `SELECT * FROM c`;

    // Validate untrusted input and use secure platform APIs
    if (context.bindingData.query) {
      const sanitizedQuery = context.bindingData.query.replace(/[^\w\s]/gi, '');
      query = `SELECT * FROM c WHERE c.name LIKE '%${sanitizedQuery}%'`;
    }

    // Apply least privilege and explicit allowlists where relevant
    const database = cosmosDbClient.database(databaseName);
    const collection = database.collection(collectionName);
    const results = await collection.queryDocuments(query);

    // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
    context.log(`Results: ${JSON.stringify(results)}`);
  },
});